lessons.starter_code:
# 敌人类
class Enemy:
    def __init__(self, name, hp, attack, exp_reward, gold_reward):
        self.name = name
        self.hp = hp
        self.max_hp = hp
        self.attack = attack
        self.exp_reward = exp_reward
        self.gold_reward = gold_reward

    def is_alive(self):
        return self.hp > 0

    def take_damage(self, damage):
        self.hp -= damage
        return damage

# 创建敌人模板
def create_slime():
    return Enemy("史莱姆", 30, 8, 15, 10)

def create_goblin():
    return Enemy("哥布林", 50, 12, 30, 25)

def create_dragon():
    return Enemy("巨龙", 200, 25, 100, 200)

# 测试
enemies = [create_slime(), create_goblin(), create_dragon()]
print("=== 敌人列表 ===")
for enemy in enemies:
    print(f"{enemy.name}: HP={enemy.hp} ATK={enemy.attack} EXP={enemy.exp_reward} GOLD={enemy.gold_reward}")

